SELECT name 
FROM tbl_dining 
WHERE dining_id = #{dining_id}

SELECT COUNT(*) FROM dining_reservations
AND (guest_name LIKE '%' || #{keyword} || '%' OR guest_phone LIKE '%' || #{keyword} || '%')
AND status = #{status}

SELECT * FROM ( SELECT rownum AS rno, T.* FROM ( SELECT R.dining_reservation_id as diningReservationId, (SELECT D.NAME FROM TBL_DINING D WHERE D.DINING_ID = R.dining_id) as diningName, R.guest_name as guestName, R.guest_phone as guestPhone, R.res_date as resDate, R.res_time as resTime, R.adult_count as adultCount, R.child_count as childCount, R.infant_count as infantCount, R.status as status, R.fk_member_no as fkMemberNo, R.created_at as createdAt FROM dining_reservations R
AND (R.guest_name LIKE '%' || #{keyword} || '%' OR R.guest_phone LIKE '%' || #{keyword} || '%')
AND R.status = #{status}
ORDER BY R.res_date DESC, R.res_time DESC ) T ) WHERE rno BETWEEN #{startRow} AND #{endRow}

mapper.update:
UPDATE dining_reservations
SET status = #{status}
WHERE dining_reservation_id = #{resId}

mapper.select:

SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
FROM tbl_dining d
WHERE d.dining_id = #{diningId}
  AND d.active_yn = 'Y'

  AND NOT EXISTS (
      SELECT 1 FROM tbl_dining_block b
      WHERE b.fk_dining_id = d.dining_id
        AND b.block_date = #{resDate}
        AND (b.block_time = 'ALL' OR b.block_time = #{resTime})
  )

  AND (
      SELECT COALESCE(SUM(r.adult_count + r.child_count + r.infant_count), 0)
      FROM dining_reservations r
      WHERE r.dining_id = d.dining_id
        AND r.res_date = #{resDate}
        AND r.res_time = #{resTime}
        AND r.status != 'CANCELED' 
  ) + (TO_NUMBER(#{adult_count}) + TO_NUMBER(#{child_count}) + TO_NUMBER(#{infant_count})) <= d.max_total_capacity

SELECT COUNT(*)
FROM tbl_dining_block
WHERE FK_DINING_ID = #{diningId}
  AND BLOCK_DATE = #{resDate}
  AND (
      BLOCK_TIME = 'ALL'           
      OR BLOCK_TIME = #{resTime}  
  )

SELECT 'ALL' as res_time
FROM tbl_dining_block
WHERE fk_dining_id = #{diningId} 
  AND block_date = #{resDate} 
  AND block_time = 'ALL'

UNION

SELECT block_time as res_time
FROM tbl_dining_block
WHERE fk_dining_id = #{diningId} 
  AND block_date = #{resDate} 
  AND block_time != 'ALL'

UNION

SELECT r.res_time
FROM dining_reservations r
JOIN tbl_dining d ON r.dining_id = d.dining_id
WHERE r.dining_id = #{diningId} 
  AND r.res_date = #{resDate} 
  AND r.status != 'CANCELED'
GROUP BY r.res_time, d.max_total_capacity
HAVING SUM(r.adult_count + r.child_count + r.infant_count) >= d.max_total_capacity

